-export function getWorkstationPosition(roomType: string): { x: number; y: number } {
-  // Define workstation positions relative to room coordinates (0-1 range)
-  // These are offsets to be scaled and added to room position in agents.tsx
+export function drawCharacter(
+  ctx: CanvasRenderingContext2D,
+  characterType: CharacterType,
+  palette: Record<string, string>,
+  x: number,
+  y: number,
+  s: number,
+  timestamp: number,
+  flipH = false,
+) {
+  const frames = IDLE_FRAMES_MAP[characterType] || [KING_SPRITE];
+  const frameIndex = getIdleAnimationFrame(timestamp);
+  // Clamp frame index to available frames count
+  const frame = frames[frameIndex % frames.length];
+
+  // Breathing vertical offset: subtle sine wave offset between -1 and 1 pixels
+  const breathOffset = Math.floor(Math.sin(timestamp / 500) * 1);
+
+  // Draw the sprite with breathing offset
+  drawSpriteDef(ctx, frame, palette, x, y, s, flipH, breathOffset);
+}
